// Group sales by sale_number
const items = $input.all();
const salesBySaleNumber = new Map();

items.forEach(item => {
  const saleNum = item.json.sale_number;
  if (!salesBySaleNumber.has(saleNum)) {
    salesBySaleNumber.set(saleNum, {
      sale_number: saleNum,
      sale_status: item.json.sale_status,
      payment_method: item.json.payment_method,
      sale_total: parseFloat(item.json.sale_total_amount),
      sale_time: item.json.sale_time,
      items: []
    });
  }

  salesBySaleNumber.get(saleNum).items.push({
    drug_name: item.json.brand_name || item.json.generic_name,
    description: item.json.package_description,
    quantity: item.json.quantity,
    unit_price: parseFloat(item.json.unit_price),
    total_price: parseFloat(item.json.total_price),
    stock_available: item.json.quantity_on_hand || 0
  });
});

// Build Slack blocks
const blocks = [];
let grandTotal = 0;

// Time range header
const firstSale = items[0].json.sale_time;
const lastSale = items[items.length - 1].json.sale_time;
const startTime = new Date(firstSale).toLocaleTimeString('en-US', { 
  hour: '2-digit', 
  minute: '2-digit' 
});
const endTime = new Date(lastSale).toLocaleTimeString('en-US', { 
  hour: '2-digit', 
  minute: '2-digit' 
});

blocks.push({
  type: "header",
  text: {
    type: "plain_text",
    text: `💊 Sales: ${startTime} - ${endTime}`
  }
});

blocks.push({ type: "divider" });

// For each sale
salesBySaleNumber.forEach(sale => {
  grandTotal += sale.sale_total;

  // Sale header
  blocks.push({
    type: "section",
    text: {
      type: "mrkdwn",
      text: `*Sale: ${sale.sale_number}*\n` +
            `Status: ${sale.sale_status} | ` +
            `Payment: ${sale.payment_method} | ` +
            `Time: ${new Date(sale.sale_time).toLocaleTimeString()}`
    }
  });

  // Items
  sale.items.forEach(item => {
    blocks.push({
      type: "section",
      text: {
        type: "mrkdwn",
        text: `• *${item.drug_name}*\n` +
              `  ${item.description}\n` +
              `  ${item.quantity} × $${item.unit_price.toFixed(2)} = ` +
              `*$${item.total_price.toFixed(2)}*\n` +
              `  📦 Stock: ${item.stock_available} available`
      }
    });
  });

  // Sale total
  blocks.push({
    type: "section",
    text: {
      type: "mrkdwn",
      text: `*Total Amount for ${sale.sale_number}:* $${sale.sale_total.toFixed(2)}`
    }
  });

  blocks.push({ type: "divider" });
});

// Footer summary
blocks.push({
  type: "context",
  elements: [{
    type: "mrkdwn",
    text: `📈 *${salesBySaleNumber.size}* sale(s) | ` +
          `💰 *Grand Total: $${grandTotal.toFixed(2)}*`
  }]
});

// Return blocks as array (NOT stringified!)
return [{
  json: {
    blocks: blocks,
    sales_count: salesBySaleNumber.size,
    grand_total: grandTotal,
    time_range: `${startTime} - ${endTime}`
  }
}];

// Prepare payload for Slack API
const data = $input.first().json;

return [{
  json: {
    channel: "sales-team",
    text: "New sales recorded",
    blocks: data.blocks
  }
}];
